const PB_URL=($('Config').first().json.pbUrl||'').replace(/\/+$/,'');
const token=$('PB Auth').first().json.token; const pbH={Authorization:token};
const body=($('Webhook').first().json.body)||{};
const force = body.force === true;
// Clear mode (UI 'Clear queue'): delete all still-queued rows (leaves processing/done).
if(body.clear){ let cleared=0; while(true){ const r=await this.helpers.httpRequest({method:'GET',url:PB_URL+'/api/collections/scrape_queue/records',qs:{filter:"status='queued'",perPage:200,fields:'id'},headers:pbH,json:true}); const items=r.items||[]; if(!items.length)break; await Promise.all(items.map(it=>this.helpers.httpRequest({method:'DELETE',url:PB_URL+'/api/collections/scrape_queue/records/'+it.id,headers:pbH,json:true}).catch(()=>{}))); cleared+=items.length; if(items.length<200)break; } return [{json:{cleared}}]; }
let ids = [];
if (Array.isArray(body.ids) && body.ids.length){ ids = body.ids.filter(Boolean); }
else if (body.filter){ let page=1; while(true){ const r=await this.helpers.httpRequest({method:'GET',url:PB_URL+'/api/collections/clubs/records',qs:{filter:body.filter,perPage:500,page,fields:'id'},headers:pbH,json:true}); ids=ids.concat((r.items||[]).map(x=>x.id)); if(page>=(r.totalPages||1))break; page++; } }
ids=[...new Set(ids)];
const now=new Date().toISOString();
const findRow=async(club)=>{const r=await this.helpers.httpRequest({method:'GET',url:PB_URL+'/api/collections/scrape_queue/records',qs:{filter:'club="'+club+'"',perPage:1},headers:pbH,json:true});return (r.items&&r.items[0])||null;};
let created=0, requeued=0;
const upsert=async(club)=>{ try{ await this.helpers.httpRequest({method:'POST',url:PB_URL+'/api/collections/scrape_queue/records',headers:pbH,body:{club,status:'queued',force,enqueued_at:now,attempts:0},json:true}); created++; }
  catch(e){ try{ const ex=await findRow(club); if(ex){ await this.helpers.httpRequest({method:'PATCH',url:PB_URL+'/api/collections/scrape_queue/records/'+ex.id,headers:pbH,body:{status:'queued',force,enqueued_at:now},json:true}); requeued++; } }catch(_){}} };
for(let i=0;i<ids.length;i+=50){ await Promise.all(ids.slice(i,i+50).map(upsert)); }
return [{json:{enqueued:created,requeued,total:ids.length}}];
